import React from "react";

export default function FloatingOrb({ top, left, size, color, delay = 0 }) {
  const baseColor = color || "var(--primary)";

  return (
    <div 
      style={{
        position: "absolute",
        top, 
        left,
        width: size,
        height: size,
        borderRadius: "50%",
        
        background: `radial-gradient(circle at 30% 30%, 
          #ffffff 0%, 
          color-mix(in srgb, ${baseColor} 15%, transparent) 60%, 
          color-mix(in srgb, ${baseColor} 30%, transparent) 100%
        )`,
        
        border: `1px solid color-mix(in srgb, ${baseColor} 40%, transparent)`,
        
        boxShadow: `0 10px 30px rgba(0, 70, 173, 0.05), inset 0 2px 4px rgba(255, 255, 255, 0.8)`,
        
        animation: `float 6s ease-in-out ${delay}s infinite`,
        pointerEvents: "none",
        zIndex: 2,
      }} 
    />
  );
}
